// distance squared
inline function distance2(p0, p1)
{
	local dx = p1.x - p0.x;
	local dy = p1.y - p0.y;
	return dx * dx + dy * dy;
}

// angle between two points
inline function angleBetween(p0, p1)
{
	local dx = p1.x - p0.x;
	local dy = p1.y - p0.y;
	// convert atan() to atan2()
	local a = Math.atan(dy / dx);
	if(dx > 0)
	{
		if(dy < 0) 
			a += Math.PI;
		else
			a -= Math.PI;
	}
	return a;
}

